npc_base[2] = createObject({
    b_i: 2,
    b_t: BASE_TYPE.NPC,
    name: 'General Shopkeeper',
    type: OBJECT_TYPE.SHOP,
    img: {
        hash: '33 0 66 38 72 0 0 0 0 0 0 0'
    },
    params: {
        health: 99,
        desc: 'She buys all your items for 15% of their value'
    },
    temp: {
        health: 99,
        total_defense: 99,
        total_strength: 99,
        total_accuracy: 99,
        content: [],
        general: 0.15
    },
    activities: [
        ACTIVITIES.TRADE_WITH,
        ACTIVITIES.INSPECT
    ],
    fn: {
        'trade with': function (a, b) {
            selected = obj_g(a);
            if (needsProximity(b, a, 1, !0)) {
                if (general_shopkeeper_dialog_shown ||
                    Report.can_report(skills[0]) ||
                    12 == current_map)
                    return DEFAULT_FUNCTIONS['trade with'](a, b);
                Popup.dialog(_ti('Warning: The General Shopkeeper buys all items, but at a much lower price than specialized NPCs. You can find specialized NPC in the in-game wiki.'), function () {
                    general_shopkeeper_dialog_shown = !0;
                    return DEFAULT_FUNCTIONS['trade with'](a, b);
                }, 'big');
            }
            return !0;
        }
    }
}, 1);
