npc_base[208] = createObject({
    b_i: 208,
    b_t: BASE_TYPE.NPC,
    name: 'Activities Instructor',
    type: OBJECT_TYPE.SHOP,
    img: {
        hash: '3 0 219 197 72 0 0 0 0 0 0 0'
    },
    params: {
        health: 99
    },
    temp: {
        health: 99,
        total_defense: 99,
        total_strength: 99,
        total_accuracy: 99,
        content: []
    },
    activities: [
        ACTIVITIES.TALK,
        ACTIVITIES.INSPECT
    ],
    fn: {
        talk: function (a, b) {
            needsProximity(b, a, 1, !0) &&
                Popup.dialog(_tq('There are many activities that can be done in addition to levelling up skills.'), function () {
                    Popup.dialog(_tq('You can find and hunt bosses like [teal]Cannibal plant[/teal] for special loot. Most maps have a boss monster.'), function () {
                        Popup.dialog(_tq('You can find monsters and resources with the [yellow]/find[/yellow] command, Example: [yellow]/find cannibal plant[/yellow].'), function () {
                            Popup.dialog(_tq('You can participate in various activities such as [teal]Cathedral[/teal], [teal]Elemental towers[/teal], [teal]World bosses[/teal] and [teal]Minigames[/teal].'), function () {
                                Popup.dialog(_tq('In addition complete different quests like [yellow]Kill quests[/yellow], [yellow]Skill quests[/yellow], [yellow]Party quests[/yellow].'), function () {
                                });
                            });
                            12 == current_map &&
                                interactiveArrow('cathedral', function () {
                                    return selected_object &&
                                        selected_object.id == PlayerQuests[1].positions.cathedral.id;
                                }, PlayerQuests[1].positions.cathedral, 'down', 30000);
                        });
                    });
                    12 == current_map &&
                        interactiveArrow('cannibal_plant', function () {
                            return selected_object &&
                                selected_object.id == PlayerQuests[1].positions.cannibal_plant.id;
                        }, PlayerQuests[1].positions.cannibal_plant, 'down', 30000);
                });
        }
    }
}, 1);
