npc_base[270] = createObject({
    b_i: 270,
    b_t: BASE_TYPE.NPC,
    name: 'Quest Instructor',
    type: OBJECT_TYPE.SHOP,
    img: {
        hash: '18 0 207 185 72 0 0 0 0 0 78 0'
    },
    params: {
        health: 99
    },
    temp: {
        health: 99,
        total_defense: 99,
        total_strength: 99,
        total_accuracy: 99,
        content: []
    },
    activities: [
        ACTIVITIES.TALK,
        ACTIVITIES.INSPECT
    ],
    fn: {
        talk: function (a, b) {
            needsProximity(b, a, 1, !0) &&
                Popup.dialog(_tq('Finishing [teal]Quests[/teal], can be very rewarding.'), function () {
                    Popup.dialog(_tq('Click on Quests tab to see the ongoing quests.'), function () {
                        Popup.dialog(_tq('Clicking on a quest shows a possible location where it can be completed. Map name is visible when you hover or click the minimap on top left corner.'), function () {
                            Popup.dialog(_tq('You can reset a completed quest to get a new reward with a [yellow]Repeat Quest Permission[/yellow]') + '<div style=\'' + Items.get_background_image(1031) + 'width:32px;height:32px;margin-left:42%;\'></div>', function () {
                                12 == current_map &&
                                    (Socket.send('interact', {
                                        target_id: a.id
                                    }),
                                        interactiveArrow('combat_instructor', function () {
                                            return selected_object &&
                                                selected_object.id == PlayerQuests[1].positions.combat_instructor.id;
                                        }, PlayerQuests[1].positions.combat_instructor, 'down', 60000));
                            });
                        });
                    });
                    var b = Popup.active_popup_text;
                    interactiveArrow('quests', function () {
                        return FormHelper.is_form_visible('quests') ||
                            Popup.active_popup_text != b;
                    }, {
                        id: 'gui_quests'
                    }, 'down', 60000);
                    interactiveArrow('quests_toolbar', function () {
                        return FormHelper.is_form_visible('quests') ||
                            Popup.active_popup_text != b;
                    }, {
                        id: 'quest_toolbar'
                    }, 'down', 60000);
                    interactiveArrow('quests_kill_button', function () {
                        return 'active' == Quests.last_opened;
                    }, {
                        id: 'kill_quests_button'
                    }, 'down', 60000);
                });
        },
        interact: function (a, b) {
            12 != b.map ||
                0 < Inventory.get_item_count_include_pet(b, 1031) ||
                Items.give_to_player(b, 1031);
        }
    }
}, 1);
