npc_base[306] = createObject({
    b_i: 306,
    b_t: BASE_TYPE.NPC,
    name: 'Magic Instructor',
    type: OBJECT_TYPE.SHOP,
    img: {
        hash: '18 0 90 54 72 1 0 54 166 46 12 5'
    },
    params: {
        health: 99
    },
    temp: {
        health: 99,
        total_defense: 99,
        total_strength: 99,
        total_accuracy: 99,
        content: []
    },
    activities: [
        ACTIVITIES.TALK,
        ACTIVITIES.INSPECT
    ],
    fn: {
        talk: function (a, b) {
            needsProximity(b, a, 1, !0) &&
                Popup.dialog(_tq('To use [teal]magic[/teal] you need to equip a magic pouch.'), function () {
                    Popup.dialog(_tq('Also you need to put some spells into the magic pouch by clicking on them while the pouch is equipped. Each spell has a short cooldown after use.'), function () {
                        Socket.send('interact', {
                            target_id: a.id
                        });
                        Popup.dialog(_tq('To do magic damage, you need to click on the spell icon while in combat. Alternatively you can press numbers on your keyboard.'), function () {
                        });
                    });
                });
        },
        interact: function (a, b) {
            12 == b.map &&
                (0 == Inventory.get_item_count_include_pet(b, 444) &&
                    Items.give_to_player(b, 444),
                    0 == Inventory.get_item_count_include_pet(b, 877) &&
                        Items.give_to_player(b, 877),
                    0 == Inventory.get_item_count_include_pet(b, 1889) &&
                        Items.give_to_player(b, 1889),
                    0 == Inventory.get_item_count_include_pet(b, 868) &&
                        Items.give_to_player(b, 868),
                    100 > skills[b.id].magic.xp ? 0 != Inventory.get_item_count_include_pet(b, 402) ||
                        'undefined' != typeof b.params.magics[0] &&
                            0 != b.params.magics[0].count ||
                        Items.give_to_player(b, 402) : Player.send_message_tq(b.id, 'Move to the next room', {}, COLOR.TEAL));
        }
    }
}, 1);
